import{_ as d,o as r,c as n,ag as a}from"./chunks/framework.DXGyWiRo.js";const e="/images/lekt1401.jpg",i="/images/lekt1405.jpg",s="/images/lekt1404.jpg",p="/images/lekt1403.jpg",u="/images/lekt1402.jpg",v=JSON.parse('{"title":"Lektion 14","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion14.md","filePath":"lektionen/lektion14.md"}'),l={name:"lektionen/lektion14.md"};function o(h,t,m,c,b,g){return r(),n("div",null,[...t[0]||(t[0]=[a('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-14" tabindex="-1">Lektion 14 <a class="header-anchor" href="#lektion-14" aria-label="Permalink to &quot;Lektion 14&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>14.1. Der Ausdruck des Verhältnisses von durch Substantive Bezeichnetem: der Genetiv (ṣaṣṭhī f. = षष्टी = sechste Kasusendung)</li><li>14.2. Bildung der Genetivformen (ṣāṣṭhī f. = षष्ठी)</li><li>14.3. Weiteres zum Gebrauch des Genetiv (षष्ठी)</li><li>14.4. Wortliste</li><li>14.5. Subhāṣitāni = सुभाषितानि = Sprichwörter</li><li>14.6. Übung</li></ul><h2 id="_14-1-der-ausdruck-des-verhaltnisses-von-durch-substantive-bezeichnetem-der-genetiv-sasthi-f-षष्टी-sechste-kasusendung" tabindex="-1">14.1. Der Ausdruck des Verhältnisses von durch Substantive Bezeichnetem: der Genetiv (ṣaṣṭhī f. = षष्टी = sechste Kasusendung) <a class="header-anchor" href="#_14-1-der-ausdruck-des-verhaltnisses-von-durch-substantive-bezeichnetem-der-genetiv-sasthi-f-षष्टी-sechste-kasusendung" aria-label="Permalink to &quot;14.1. Der Ausdruck des Verhältnisses von durch Substantive Bezeichnetem: der Genetiv (ṣaṣṭhī f. = षष्टी = sechste Kasusendung)&quot;">​</a></h2><p>Soll das Verhältnis des durch zwei Substantive ausgedrückten bezeichnet werden, verwendet man den Genetiv (ṣaṣṭī f. &quot;sechste Kasusendung&quot;). Der Genetiv unterscheidet sich von allen übrigen Kasus dadurch, dass er -- mit wenigen Ausnahmen -- nicht zur näheren Bestimmung der durch das Verb ausgedrückten Handlung dient, sondern zum Ausdruck des Verhältnisses zwischen Personen oder Sachen, die durch Substantive bezeichnet werden. Häufig steht der Genetiv auf die Frage: Wessen?</p><p>Beispiele:</p><blockquote><p>कवेः पुत्रः &quot;Des Dichters Sohn&quot;</p><p>धन्स्य लोभः &quot;Gier nach Reichtum&quot;</p><p>नगरस्यार्धम् &quot;Die Hälfte der Stadt&quot;</p><p>रामस्य कृतम् &quot;Die / Eine Tat Rāmas&quot;</p></blockquote><p>Die normale Wortstellung ist:</p><p>Bestimmendes Wort im Genativ - Näher bestimmtes Substantiv in einem anderen Kasus</p><p>Genetiv und PPP:</p><p>Bei PPPs kann der Genetiv statt des Instrumentalis (tṛtīyā) für den Agens (kartṛ) stehen; In der Konstruktion mit dem Instrumentalis wird das PPP als passive Verbalform betrachtet (das im Instrumentalis Stehende bezeichnet den Agens), in der Konstruktion mit dem Genetiv wird das PPP als Substantiv bzw. Adjektiv betrachtet (das im Genetiv Stehende also nicht eigentlich als Agens).</p><p>Nach Pāṇini 2.3.67 steht beim PPP der Genetiv, wenn das PPP präsentische Bedeutung hat (siehe oben), der Instrumentalis, wenn das PPP Vergangenheitsbedeutung hat.:</p><p>रामस्येष्टं फलम् &quot;Die von Rāma gewünschte Frucht = Die Frucht, die Rāma gegenwärtig wünscht&quot;</p><p>रामेणेष्टं फलम् &quot;Die Frucht, die Rāma gewünscht hat&quot;</p><p>Selbstverständlich steht bei einem PPP Neutrum Singular, das als Verbalabstraktum - also als Substantiv - gebraucht wird, der Genetiv.</p><h2 id="_14-2-bildung-der-genetivformen-sasthi-f-षष्ठी" tabindex="-1">14.2. Bildung der Genetivformen (ṣāṣṭhī f. = षष्ठी) <a class="header-anchor" href="#_14-2-bildung-der-genetivformen-sasthi-f-षष्ठी" aria-label="Permalink to &quot;14.2. Bildung der Genetivformen (ṣāṣṭhī f. = षष्ठी)&quot;">​</a></h2><p>Der Genetiv wird bei Verbalstämmen mit Stammabstufung vom schwachen Stamm gebildet.</p><p>Genetiv von konsonantisch auslautenden Stämmen:</p><p>Nach Konsonant sind die regelmäßigen Genetivendungen:</p><ul><li>Singular: -as</li><li>Plural: -ām</li></ul><p>z.B.</p><blockquote><table tabindex="0"><thead><tr><th>Nominalstamm</th><th>Schwacher Stamm</th><th>Genetiv Singular</th><th>Genetiv Plural</th></tr></thead><tbody><tr><td>guṇa-vant-</td><td></td><td></td><td></td></tr><tr><td>गुणवन्त्</td><td>guṇa-vat-</td><td></td><td></td></tr><tr><td>गुणवत्</td><td>guṇa-vat-as</td><td></td><td></td></tr><tr><td>गुणवतस्</td><td>guṇa-vat-ām</td><td></td><td></td></tr><tr><td>गुणवताम्</td><td></td><td></td><td></td></tr><tr><td>paśu-mant-</td><td></td><td></td><td></td></tr><tr><td>पशुमन्त्</td><td>paśu-mat-</td><td></td><td></td></tr><tr><td>पशुमत्</td><td>paśu-mat-as</td><td></td><td></td></tr><tr><td>पशुमतस्</td><td>paśu-mat-ām</td><td></td><td></td></tr><tr><td>पशुमताम्</td><td></td><td></td><td></td></tr></tbody></table></blockquote><p>Genetiv von vokalisch auslautenden Stämmen, außer einsilbigen Wurzelnomina und diphtongisch auslautenden Stämmen:</p><p>Plural:</p><p>Der Genetiv Plural vokalisch auslautender Stämme wird so gebildet:</p><p>-langer auslautender Vokal des Stammes + -nām</p><p>z.B.</p><blockquote><table tabindex="0"><thead><tr><th>Nominalstamm</th><th>Genetiv Plural</th></tr></thead><tbody><tr><td>deva m.</td><td></td></tr><tr><td>देव</td><td>devā-nām</td></tr><tr><td>देवानाम्</td><td></td></tr><tr><td>phala n.</td><td></td></tr><tr><td>फल</td><td>phalā-nām</td></tr><tr><td>फलानाम्</td><td></td></tr><tr><td>devatā f.</td><td></td></tr><tr><td>देवता</td><td>devatā-nām</td></tr><tr><td>देवतानाम्</td><td></td></tr><tr><td>kavi m.</td><td></td></tr><tr><td>कवि</td><td>kavī-nām</td></tr><tr><td>कवीनाम्</td><td></td></tr><tr><td>śruti f.</td><td></td></tr><tr><td>श्रुति</td><td>śrutī-nām</td></tr><tr><td>श्रुतीनाम्</td><td></td></tr><tr><td>devī f.</td><td></td></tr><tr><td>देवी</td><td>devī-nām</td></tr><tr><td>देवीनाम्</td><td></td></tr><tr><td>paśu m.</td><td></td></tr><tr><td>पशु</td><td>paśū-nām</td></tr><tr><td>पशूनाम्</td><td></td></tr><tr><td>dhenu f.</td><td></td></tr><tr><td>धेनु</td><td>dhenū-nām</td></tr><tr><td>धेनूनाम्</td><td></td></tr></tbody></table></blockquote><p>Genetiv Singular vokalisch auslautender Stämme:</p><table><tbody><tr><td colspan="2">**Der Genetiv Singular vokalisch auslautender Stämme wird unregelmäßig gebildet und ist gut auswendig zu lernen.**</td></tr><tr><td>**Stamm**</td><td>**Genetiv Singular**</td></tr><tr><td>deva m.<br>देव</td><td>**devasya<br>देवस्य**</td></tr><tr><td>phala n.<br>फल</td><td>**phalasya<br>फलस्य**</td></tr><tr><td>devatā f.<br>देवता</td><td>**devatāyās<br>देवतायास्**</td></tr><tr><td>kavi m.<br>कवि</td><td>**kaves<br>कवेस्**</td></tr><tr><td>paśu m.<br>पशु</td><td>**paśos<br>पशोस्**</td></tr><tr><td>devī f.<br>देवी</td><td>**devyās<br>देव्यास्**</td></tr><tr><td>śruti f.<br>श्रुति</td><td>**śrutes / śrutyās**<br>**श्रुतेस् / श्रुत्यास्व्**(d.h. entweder wir kavi oder wie devī)<br></td></tr><tr><td>dhenu f.<br>धेनु</td><td>**dhenos / dhenvās<br>धेनोस् / धेन्वास्**(d.h. entweder wir paśu oder wie mehrsilbige Feminina auf -ū)</td></tr></tbody></table><p>Fragepronomen und Demonstrativpronomen:</p><table tabindex="0"><thead><tr><th></th><th></th><th>kim</th><th>tad</th><th>etad</th><th>idam</th></tr></thead><tbody><tr><td>Maskulinum</td><td></td><td></td><td></td><td></td><td></td></tr><tr><td>/ Neutrum</td><td>Genetiv</td><td></td><td></td><td></td><td></td></tr><tr><td>Singular</td><td>kasya</td><td></td><td></td><td></td><td></td></tr><tr><td>कस्य</td><td>tasya</td><td></td><td></td><td></td><td></td></tr><tr><td>तस्य</td><td>etasya</td><td></td><td></td><td></td><td></td></tr><tr><td>एतस्य</td><td>asya</td><td></td><td></td><td></td><td></td></tr><tr><td>अस्य</td><td></td><td></td><td></td><td></td><td></td></tr><tr><td></td><td>Genetiv</td><td></td><td></td><td></td><td></td></tr><tr><td>Plural</td><td>keṣām</td><td></td><td></td><td></td><td></td></tr><tr><td>केषाम्</td><td>teṣām</td><td></td><td></td><td></td><td></td></tr><tr><td>तेषाम्</td><td>eteṣām</td><td></td><td></td><td></td><td></td></tr><tr><td>एतेषाम्</td><td>eṣām</td><td></td><td></td><td></td><td></td></tr><tr><td>एषाम्</td><td></td><td></td><td></td><td></td><td></td></tr><tr><td>Femininum</td><td>Genetiv</td><td></td><td></td><td></td><td></td></tr><tr><td>Singular</td><td>kasyās</td><td></td><td></td><td></td><td></td></tr><tr><td>कस्यास्</td><td>tasyās</td><td></td><td></td><td></td><td></td></tr><tr><td>तस्यास्</td><td>etasyās</td><td></td><td></td><td></td><td></td></tr><tr><td>एतस्यास्</td><td>asyās</td><td></td><td></td><td></td><td></td></tr><tr><td>अस्यास्</td><td></td><td></td><td></td><td></td><td></td></tr><tr><td></td><td>Genetiv</td><td></td><td></td><td></td><td></td></tr><tr><td>Plural</td><td>kāsām</td><td></td><td></td><td></td><td></td></tr><tr><td>कासाम्</td><td>tāsām</td><td></td><td></td><td></td><td></td></tr><tr><td>तासाम्</td><td>etāsām</td><td></td><td></td><td></td><td></td></tr><tr><td>एतासाम्</td><td>āsām</td><td></td><td></td><td></td><td></td></tr><tr><td>आसाम्</td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table><p>Formengleichheit:</p><p><img src="'+e+'" alt=""></p><p>Bei allen Nominalstämmen mit Ausnahme der Maskulina und Neutra auf -a und den Pronomina ist die Form des Genetiv Singular identisch mit der Form des Ablativ (pañcamī &quot;fünfte Kasusendung&quot;) Singular!</p><p><img src="'+e+'" alt=""></p><p>Beachten Sie, dass bei konsonantisch auslautenden Stämmen Ablativ und Genetiv Singular gleich lauten wie der Akkusativ Plural Maskulinum und Femininum!</p><h2 id="_14-3-weiteres-zum-gebrauch-des-genetiv-षष्ठी" tabindex="-1">14.3. Weiteres zum Gebrauch des Genetiv (षष्ठी) <a class="header-anchor" href="#_14-3-weiteres-zum-gebrauch-des-genetiv-षष्ठी" aria-label="Permalink to &quot;14.3. Weiteres zum Gebrauch des Genetiv (षष्ठी)&quot;">​</a></h2><p>Entgegen obiger Grundregel wird der genetiv verwendet, um das Objekt einiger Verben auszudrücken, z.B. bei Verben des Gedenkens:</p><blockquote><p>देवानां स्मरति &quot;Er gedenkt der Götter&quot;</p></blockquote><p>Bei all diesen verben kann das Objekt aber auch im Akkusativ stehen:</p><blockquote><p>देवान्स्मरति &quot;Er gedenkt der Götter&quot;</p></blockquote><p>Weiteres später.</p><h2 id="_14-4-wortliste" tabindex="-1">14.4. Wortliste <a class="header-anchor" href="#_14-4-wortliste" aria-label="Permalink to &quot;14.4. Wortliste&quot;">​</a></h2><p>śīla n. शील : (guter) Charakter, Sittlichkeit</p><p>bhūṣ-aṇa n भूषण : Schmuck</p><p>dīpa m. दीप : Lampe</p><p><img src="'+i+'" alt=""><br> Abb.: दीपाः<br> [Bildquelle: [srijith]. -- <a href="http://www.flickr.com/photos/srijith/1918428547/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/srijith/1918428547/</a>. -- Zugriff am 2008-12-01. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>bala n. बल् : Gewalt, Kraft, Stärke; Heereskraft, Heerschar</p><p>bāla 3 बाल : jung, kindlich, töricht ; m. Knabe</p><p>bālā f. बाला : junges Mädchen</p><p>nara m. नर : Mann, Mensch</p><p>śatru m. शत्रु : Feind</p><p>loka m. लोक : Welt; Sing. u. Plur.: die Leute, die Menschen, das Volk</p><p>jala n. जल : Wasser</p><p>jan 4 Ā (jāyate), Pass. janyate / jāyate, PPP jāta जन् जायते जन्यते जायते जात : geboren werden, entstehen, auftreten</p><p>davon:</p><blockquote><p>jan-a m. जन : Geschöpf, Mensch, Leute</p></blockquote><p>vac 2 P (vakti, keine 3. plur.!), Pass. ucyate, PPP ukta वच् वक्ति उच्यते उक्त : sagen, sprechen zu (dvitīyā)</p><p>davon:</p><blockquote><p>uk-ti f. उक्ति : Ausspruch, Wort</p><p>vac-ana n. वचन : das Sprechen, das Wort</p><p>vāk-ya n. वाक्य : Wort, Rede</p></blockquote><h2 id="_14-5-subhasitani-सुभाषितानि-sprichworter" tabindex="-1">14.5. Subhāṣitāni = सुभाषितानि = Sprichwörter <a class="header-anchor" href="#_14-5-subhasitani-सुभाषितानि-sprichworter" aria-label="Permalink to &quot;14.5. Subhāṣitāni = सुभाषितानि = Sprichwörter&quot;">​</a></h2><p>Übersetzen Sie folgende Sprichwörter und lernen Sie sie auswendig:</p><p>निचो वदति न कुरुते<br> वदति न साधुः करोत्येव ॥१॥</p><p>शीलं नरस्य भूषणम् ॥२॥</p><p>सत्येन जनानां सुखं भवति ॥३॥</p><p>पापा नराः स्वर्गं न लभन्ते ॥४॥</p><p>सत्यं लोकस्य दीपः ॥५॥</p><h2 id="_14-6-ubung" tabindex="-1">14.6. Übung <a class="header-anchor" href="#_14-6-ubung" aria-label="Permalink to &quot;14.6. Übung&quot;">​</a></h2><p>A) Bilden Sie den Genetiv Singular und Plural zu folgenden Wörtern. Geben Sie Bedeutung und Geschlecht der Wörter an:</p><p>१. अनृत</p><p>२. ऋषि</p><p>३. पाद</p><p>४. बुद्धि</p><p>५. गुरु</p><p>६. स्वर्ग</p><p>७. नगर</p><p>८. धेनु</p><p>९. द्विज</p><p>१०. मुक्ता</p><p>११. विद्या</p><p>१२. वर्ण</p><p>१३. द्विजाति</p><p>१४. रूप</p><p>१५. प्रतिग्रह</p><p>१६. सोढ</p><p>१७. नायिका</p><p>१८. साध्वी</p><p>१९. अग्नि</p><p>२०. वैश्या</p><p>२१. लोक</p><p>२२. उक्ति</p><p>२३. शत्रु</p><p>२४. सुखवन्त्</p><p>२५. पुत्रवती</p><p><img src="'+s+'" alt=""><br> Abb.: पुत्रवती<br> [Bildquelle: Eileen Delhi. -- <a href="http://www.flickr.com/photos/eileendelhi/164047682/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/eileendelhi/164047682/</a>. -- Zugriff am 2008-12-01. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p><p>२६. जल</p><p>२७. मार्ग</p><p>२८. मोक्ष</p><p>२९. शूद्रा</p><p>३०. अन्न</p><p>३१. साधु</p><p>३२. नीति</p><p>३३. योध</p><p>३४. सत्यवन्त्</p><p>३५. लाभ</p><p>३६. मोह</p><p>३७. गति</p><p>३८. प्रश्न</p><p>३९. सृष्टि</p><p>४०. नेत्र</p><p>४१. गुरुता</p><p>४२. ईश्वर</p><p>४३. कारण</p><p>४४. कृत</p><p>४५. धर्मवन्त्</p><p>४६. युद्ध</p><p>४७. दर्शन</p><p>४८. धातु</p><p>४९. गूढा</p><p>५०. ईष्टा (2 Bedeutungen)</p><p>५१. उदित</p><p>५२. इदम्</p><p>५३. किम्</p><p><img src="'+p+'" alt=""><br> Abb.: अयं बालः कस्याः पुत्रः ।<br> Galtaji bei Jaipur (जयपुर)<br> [Bildquelle: Robert Brauneis. -- <a href="http://www.flickr.com/photos/robertbrauneis/2323030267/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/robertbrauneis/2323030267/</a>. -- Zugriff am 2008-12-01. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p><p>B) Übersetzen Sie:</p><p>१. ब्राह्मणस्य पुत्रो ब्राह्मण्या ग्रामं गतः । (2 Möglichkeiten)</p><p>२. यज्ञस्याग्निनान्नं दग्धम् ।</p><p>३. बुद्धः स्तयस्य बुद्ध्या मुक्तः ।</p><p>४. अधर्मो ऽनृतस्य वदनमित्यृषयो वदन्ति ।</p><p>५. नरा देवानां यज्ञैर्न मुच्यन्ते ।</p><p>६. बलवन्तः क्षत्रियाः शत्रूणां धनवन्ति नगराणि जयन्ति ।</p><p>७. कवेरुक्तिं शृण्वन्ति ।</p><p>८. कविर्देव्याः कृतं वदति ।</p><p>९. द्विजाः पशोर्लाभमिच्छन्ति ।</p><p>१०. रामः पुण्यवतो गुरोर्मन्त्रस्य स्मरति ।</p><p>११. अयं बालः कस्याः पुत्रः ।</p><p>१२. केषामिमानि गृहाणि ।</p><p>१३. कस्यान्नमनेनर्षिणेष्टम् ।</p><p><img src="'+u+'" alt=""><br> Abb.: केषामिमानि गृहाणि ।<br> Fischerdorf, Kerala (കേരളം)<br> [Bildquelle: FriskoDude. -- <a href="http://www.flickr.com/photos/friskodude/1148923/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/friskodude/1148923/</a>. -- Zugriff am 2008-12-01. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p>',141)])])}const f=d(l,[["render",o]]);export{v as __pageData,f as default};
